public checkAndSetWantParams(): boolean {
  this._sandboxBundleName = FileUtils.getParamOrDefault(this._want.parameters, Constants.PARAMS_BUNDLE_NAME, '');
  if (isInvalidStr(this._sandboxBundleName)) {
    HiLog.error(TAG, 'invalid bundleName in want.parameters');
    return false;
  }
  this._uri = this._want.uri as string;
  if (isInvalidStr(this._uri) || !isValidPath(this._uri) || !this.CheckSuffixByUri()) {
    HiLog.error(TAG, 'invalid uri in want.uri');
    return false;
  }
  let strArray: string[] = this._uri.split('/');
  this._fileName = strArray[strArray.length - 1];
  const tempRandom = Date.now() + String(Math.random()).substring(Constants.RAND_START, Constants.RAND_END);
  this._requestId = FileUtils.anonymizedFileName(this._fileName) + tempRandom;
  HiLog.info(TAG, `checkAndSetWantParams requestId ${this._requestId}`);
  this._callerBundleName =
    FileUtils.getParamOrDefault(this._want.parameters, Constants.PARAMS_CALLER_BUNDLE_NAME, '');
  if (isInvalidStr(this._callerBundleName)) {
    HiLog.error(TAG, 'invalid callerBundleName');
    return false;
  }
  this._pluginId =
    (this._want.parameters?.[Constants.PARAMS_DLP_CONNECTION_PLUGIN_ID] as DlpConnectionPluginIdObj)?.id;
  this._callerAppId = FileUtils.getParamOrDefault(this._want.parameters, Constants.PARAMS_CALLER_APP_IDENTIFIER, '');
  let checkPluginId: boolean = this.checkPermissionWithPluginId();
  if (!checkPluginId) {
    HiLog.error(TAG, 'checkPermissionWithPluginId failed');
    return false;
  }
  this._sandboxAbilityName = FileUtils.getParamOrDefault(this._want.parameters, Constants.PARAMS_ABILITY_NAME, '');
  if (isInvalidStr(this._sandboxAbilityName)) {
    HiLog.error(TAG, 'invalid abilityName');
    return false;
  }
  this._sandboxModuleName = FileUtils.getParamOrDefault(this._want.parameters, Constants.PARAMS_MODULE_NAME, '');
  return true;
}

function judgeIsSandBox(want: Want) {
  return new Promise<boolean>(async resolve => {
    const callerToken: number = FileUtils.getParamOrDefault(want.parameters, Constants.PARAMS_CALLER_TOKEN, -1);
    let callerBundleName: string =
      FileUtils.getParamOrDefault(want.parameters, Constants.PARAMS_CALLER_BUNDLE_NAME, '');
    try {
      let applicationInfo = await bundleManager.getApplicationInfo(
        callerBundleName, bundleManager.ApplicationFlag.GET_APPLICATION_INFO_DEFAULT);
      if (callerToken === applicationInfo.accessTokenId) {
        resolve(false);
        return;
      }
    } catch (error) {
      HiLog.wrapError(TAG, error, 'getApplicationInfo exception');
      resolve(false);
      return;
    }
    resolve(true);
  })
}

public async setStatus(uri: string, status: DecryptStatus): Promise<Result<void>> {
  HiLog.info(TAG, `setStatus: filename: ${FileUtils.getAnonymizedFilenameByUri(uri)}, status = ${status.state}`);
  try {
    await this.lock.lockAsync(() => {
      this.statusMap.set(uri, status);
    });
    return ResultMsg.buildSuccess();
  } catch (error) {
    HiLog.wrapError(TAG, error, 'setStatus lockAsync error');
    return ResultMsg.getErrMsg(Constants.ERR_CODE_GET_LOCK_ASYNC_ERROR);
  }
}

public async addDecryptContent(uri: string, content: DecryptContent): Promise<Result<void>> {
  HiLog.info(TAG, `addDecryptContent filename: ${FileUtils.getAnonymizedFilenameByUri(uri)}`);
  this.printContentMap();
  try {
    await this.lock.lockAsync(() => {
      let decryptContentList: LinkedList<DecryptContent> =
        this.contentMap.get(uri) ?? new LinkedList<DecryptContent>();
      let hasInsert = false;
      for (const element of decryptContentList) {
        if (element.appInfo.tokenID === content.appInfo.tokenID) {
          HiLog.info(TAG, `fileid ${content.fileMetaInfo.fileId} has benn insert`);
          hasInsert = true;
          break;
        }
      }
      if (!hasInsert) {
        try {
          decryptContentList.add(content);
        } catch (error) {
          HiLog.wrapError(TAG, error, 'decryptContentList add error');
        }
      }
      this.contentMap.set(uri, decryptContentList);
      this.statusMap.set(uri, { state: DecryptState.DECRYPTED });
      this.printContentMap();
    });
    return ResultMsg.buildSuccess();
  } catch (error) {
    HiLog.wrapError(TAG, error, 'setContent lockAsync error');
    return ResultMsg.getErrMsg(Constants.ERR_CODE_GET_LOCK_ASYNC_ERROR);
  }
}

public static reportDlpFileOpenSuccess(code: number, decryptContent: DecryptContent) {
  const msg: Record<string, number | string | boolean> = DlpFileOpenReport.getCommonMsg(code, decryptContent);
  ReportToBigDataUtil.report(BigDataConstants.DLP_FILE_OPEN_EVENT, msg);
}

public static reportSecurityEvent(eventId: number, eventMsg?: object | SecurityEventMsg): void {
  let currentTimestamp: number = getCurrentTime(false);
  let formatTimestamp: string = getFormatTimestamp(currentTimestamp);
  let info: securityGuard.SecurityEvent = {
    eventId: eventId,
    version: '1.0.0',
    content: JSON.stringify(eventMsg),
    timestamp: formatTimestamp
  }
  try {
    securityGuard.reportSecurityEvent(info);
    HiLog.info(TAG, 'report security event success.');
  } catch (err) {
    HiLog.error(TAG, `report security event fail, err: ${JSON.stringify(err)}`);
  }
}
